const query = $json.query || {};
const body = $json.body || $json;
const message = query.message || body.message || '';
const projectId = query.project_id || body.project_id || ('proj-' + Date.now());
return [{ json: { message, project_id: projectId, operation: 'init', goal: message } }];

const operation = $json.operation || 'get';
const projectId = $json.project_id;
if (!projectId) return [{ json: { error: 'project_id required' } }];
const store = $getWorkflowStaticData('global');
if (operation === 'init') {
  if (store[projectId]) return [{ json: { ...store[projectId], already_exists: true } }];
  store[projectId] = {
    project_id: projectId,
    goal: $json.goal || '',
    status: 'active',
    completed_tasks: [],
    pending_tasks: [],
    files: [],
    created_at: new Date().toISOString(),
    last_updated: new Date().toISOString()
  };
  return [{ json: store[projectId] }];
}
if (operation === 'get') {
  return [{ json: store[projectId] || { project_id: projectId, exists: false } }];
}
if (operation === 'set') {
  const existing = store[projectId] || {};
  store[projectId] = { ...existing, ...$json.state, project_id: projectId, last_updated: new Date().toISOString() };
  return [{ json: store[projectId] }];
}
return [{ json: { error: `Unknown operation: ${operation}` } }];

const memory = $('Init Memory').first().json;
const message = $('Extract Input').first().json.message;
const allFiles = $json.files || [];

// Build file list for the Planner
const fileList = allFiles.map(f => f.path);

// Build lightweight API surface for Planner context
const apiSummary = [];
for (const f of allFiles) {
  if (!f.path.match(/\.(ts|tsx|js|jsx)$/) || f.path.includes('node_modules')) continue;
  const lines = (f.content || '').split('\n');
  const exports = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^export\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').replace(/=>[\s\S]*$/, '=> ...').substring(0, 120));
    }
  }
  if (exports.length > 0) {
    apiSummary.push(`${f.path}: ${exports.join('; ')}`);
  }
}

// Extract dependencies
let deps = [];
for (const f of allFiles) {
  if (f.path === 'package.json' || f.path.endsWith('/package.json')) {
    try {
      const pkg = JSON.parse(f.content);
      deps = [...Object.keys(pkg.dependencies || {}), ...Object.keys(pkg.devDependencies || {})];
    } catch(e) {}
  }
}

const staticData = $getWorkflowStaticData('global');
staticData._projectFileList = fileList;
staticData._projectApiSummary = apiSummary.join('\n');
staticData._projectDeps = deps;

return [{ json: {
  message: message,
  project_goal: memory.goal || message,
  project_id: memory.project_id,
  existing_files: fileList,
  api_summary: apiSummary.join('\n'),
  installed_packages: deps
} }];

const message = $json.message || '';
const existingFiles = $json.existing_files || [];
const apiSummary = $json.api_summary || '';
const installedPkgs = $json.installed_packages || [];

let projectContext = '';
if (existingFiles.length > 0) {
  projectContext += `

EXISTING PROJECT FILES (use these EXACT paths — do NOT invent file names):
${existingFiles.join('
')}
`;
}
if (apiSummary) {
  projectContext += `
API SURFACE (exports from each file):
${apiSummary}
`;
}
if (installedPkgs.length > 0) {
  projectContext += `
INSTALLED PACKAGES: ${installedPkgs.join(', ')}
`;
}

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen/qwen3.5-9b',
    messages: [{
      role: 'user',
      content: `You are a Senior Software Architect. Your job is to break a coding request into MULTIPLE structured tasks. Each task will be handled by a separate coder who writes files in batches of 2.

Request: ${message}${projectContext}

Output a JSON object with two fields:

1. "tasks": array of task objects. IMPORTANT: You MUST create multiple tasks. Group files by concern (e.g. styles in one task, frontend components in another, backend routes in another, config/package.json in another). Each task has:
- task_id: string like "TASK-001"
- description: detailed actionable description of what to implement, including specific requirements, color values, component names, API endpoints, and behavior. The coder cannot see the original request — your description is all they get.
- files: array of exact file paths to create or modify. List EVERY file this task needs — the coder can ONLY write files listed here. Be precise with paths (e.g. "client/src/App.tsx", not "App.tsx").
- dependencies: array of task_id strings this task depends on (empty if none)
- complexity: "low", "medium", or "high"

2. "plan_document": a concise markdown string (under 2000 chars) summarizing the architecture approach, shared interfaces, design patterns, and constraints.

RULES:
- NEVER put all files in a single task. Split by concern: styles, components, routes, config, etc.
- Each task should touch at most 3-4 files
- The description must be SELF-CONTAINED — include ALL details the coder needs (colors, class names, API contracts, state management, imports)
- Do NOT invent npm packages that may not exist — prefer CSS-only solutions unless the user specifically names a real package
- Output ONLY the raw JSON object starting with { and ending with }
- No markdown, no XML, no explanation — ONLY the JSON`
    }],
    temperature: 0.7,
    top_p: 0.8,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 1.5,
    max_tokens: 8192
  }
}];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/<\/?task>/g, '').trim();
content = content.replace(/\n+(?:Reasoning|Note|Explanation):[\s\S]*/i, '').trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
let tasks, planDocument;
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed)) {
    tasks = parsed;
    planDocument = '';
  } else {
    tasks = parsed.tasks || [parsed];
    planDocument = parsed.plan_document || '';
  }
} catch (e) {
  tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, dependencies: [], complexity: 'high', raw_output: content }];
  planDocument = '';
}
return [{ json: { tasks, plan_document: planDocument } }];

const tasks = $json.tasks || [];
const planDocument = $json.plan_document || '';
const plannerInput = $('Prepare Planner Input').first().json;
const projectId = plannerInput.project_id;
const projectGoal = plannerInput.project_goal;
const taskMap = new Map();
tasks.forEach(t => taskMap.set(t.task_id, t));
const inDegree = new Map();
const dependents = new Map();
tasks.forEach(t => {
  inDegree.set(t.task_id, 0);
  dependents.set(t.task_id, []);
});
tasks.forEach(t => {
  const deps = (t.dependencies || []).filter(d => taskMap.has(d));
  inDegree.set(t.task_id, deps.length);
  deps.forEach(d => dependents.get(d).push(t.task_id));
});
const queue = [];
tasks.forEach(t => {
  if (inDegree.get(t.task_id) === 0) queue.push(t.task_id);
});
const sorted = [];
while (queue.length > 0) {
  const id = queue.shift();
  sorted.push(taskMap.get(id));
  for (const dep of (dependents.get(id) || [])) {
    inDegree.set(dep, inDegree.get(dep) - 1);
    if (inDegree.get(dep) === 0) queue.push(dep);
  }
}
if (sorted.length < tasks.length) {
  const sortedIds = new Set(sorted.map(t => t.task_id));
  tasks.forEach(t => { if (!sortedIds.has(t.task_id)) sorted.push(t); });
}
const staticData = $getWorkflowStaticData('global');
staticData.pendingTasks = sorted.slice(1).map(t => ({ task: t, project_id: projectId, project_goal: projectGoal, plan_document: planDocument }));
staticData.taskResults = [];
const firstTask = sorted[0] || { task_id: 'T1', description: 'No tasks planned' };
return [{ json: { task: firstTask, project_id: projectId, project_goal: projectGoal, plan_document: planDocument } }];

const staticData = $getWorkflowStaticData('global');
staticData._currentTask = {
  task: $json.task,
  project_id: $json.project_id,
  project_goal: $json.project_goal,
  plan_document: $json.plan_document
};
return [$input.first()];

const trigger = $json;
const task = trigger.task || {};
const taskFiles = task.files || [];
const projectId = trigger.project_id;
const projectGoal = trigger.project_goal || '';
const planDocument = trigger.plan_document || '';
const chunkSize = 2;
const chunks = [];
for (let i = 0; i < taskFiles.length; i += chunkSize) {
  chunks.push(taskFiles.slice(i, i + chunkSize));
}
if (chunks.length === 0) chunks.push([]);
const staticData = $getWorkflowStaticData('global');
staticData.pendingChunks = chunks.slice(1).map(chunkFiles => ({
  chunk_files: chunkFiles,
  task: task,
  project_id: projectId,
  project_goal: projectGoal,
  plan_document: planDocument
}));
staticData.chunkResults = [];
return [{ json: {
  chunk_files: chunks[0],
  task: task,
  project_id: projectId,
  project_goal: projectGoal,
  plan_document: planDocument
} }];

const staticData = $getWorkflowStaticData('global');
staticData._currentChunk = {
  chunk_files: $json.chunk_files,
  task: $json.task,
  project_id: $json.project_id,
  project_goal: $json.project_goal,
  plan_document: $json.plan_document
};
return [$input.first()];

// Research: Build Project Context
// Extracts API surface and dependency manifest from ALL project files
