const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*(?:\.\w[\w.-]*|[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|txt|lock|toml|cfg|ini)|Dockerfile|Makefile|LICENSE|CHANGELOG))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path)) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
const ctx = $getWorkflowStaticData('global')._currentChunk;
return [{ json: { files, task: ctx.task, project_goal: ctx.project_goal } }];

const ctx = $getWorkflowStaticData('global')._currentChunk;
const projectId = ctx.project_id;
const chunkFiles = ctx.chunk_files || [];
const diskFiles = $('Chunk: Read Existing Files').first().json.files || [];
const generatedFiles = $json.files || [];
const existingPaths = new Set(diskFiles.map(f => f.path));
let filteredFiles = chunkFiles.length > 0
  ? generatedFiles.filter(f => chunkFiles.includes(f.path) || !existingPaths.has(f.path))
  : generatedFiles;
const pkgPaths = ['package.json', 'client/package.json'];
for (const pkgPath of pkgPaths) {
  const pkgIdx = filteredFiles.findIndex(f => f.path === pkgPath);
  if (pkgIdx !== -1) {
    const diskPkg = diskFiles.find(f => f.path === pkgPath);
    if (diskPkg) {
      try {
        const existing = JSON.parse(diskPkg.content);
        const generated = JSON.parse(filteredFiles[pkgIdx].content);
        existing.dependencies = { ...(existing.dependencies || {}), ...(generated.dependencies || {}) };
        existing.devDependencies = { ...(existing.devDependencies || {}), ...(generated.devDependencies || {}) };
        if (generated.scripts) existing.scripts = { ...(existing.scripts || {}), ...(generated.scripts || {}) };
        filteredFiles[pkgIdx] = { path: pkgPath, content: JSON.stringify(existing, null, 2) + '\n' };
      } catch(e) {}
    }
  }
}
if (filteredFiles.length === 0) {
  return [{ json: { project_id: projectId, files: [], _skipWrite: true } }];
}
return [{ json: { project_id: projectId, files: filteredFiles } }];

const ctx = $getWorkflowStaticData('global')._currentChunk;
const preparedFiles = $('Chunk: Prepare Write').first().json.files || [];
const filesWritten = preparedFiles.map(f => f.path);
return [{ json: {
  chunk_files: ctx.chunk_files || [],
  files_written: filesWritten,
  success: true
} }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.chunkResults) staticData.chunkResults = [];
staticData.chunkResults.push($json);
const hasMore = (staticData.pendingChunks || []).length > 0;
return [{ json: { ...($json), _hasMoreChunks: hasMore } }];

const staticData = $getWorkflowStaticData('global');
const pending = staticData.pendingChunks || [];
const next = pending.shift();
staticData.pendingChunks = pending;
return [{ json: next }];

const staticData = $getWorkflowStaticData('global');
const results = staticData.chunkResults || [];
staticData.chunkResults = [];
staticData.pendingChunks = [];
const allFilesWritten = [...new Set(results.flatMap(r => r.files_written || []))];
return [{ json: { files_written: allFilesWritten, chunks_processed: results.length, success: results.every(r => r.success) } }];

const ctx = $getWorkflowStaticData('global')._currentTask;
const task = ctx.task || {};
const aggregated = $json;
return [{ json: {
  task_id: task.task_id || 'unknown',
  description: task.description || '',
  files_written: aggregated.files_written || [],
  chunks_processed: aggregated.chunks_processed || 0,
  fixed: false
} }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.taskResults) staticData.taskResults = [];
staticData.taskResults.push($json);
const hasMore = (staticData.pendingTasks || []).length > 0;
return [{ json: { ...($json), _hasMoreTasks: hasMore } }];

const staticData = $getWorkflowStaticData('global');
const pending = staticData.pendingTasks || [];
const next = pending.shift();
staticData.pendingTasks = pending;
return [{ json: next }];

const staticData = $getWorkflowStaticData('global');
const results = staticData.taskResults || [];
staticData.taskResults = [];
staticData.pendingTasks = [];
return results.map(r => ({ json: r }));

const taskResults = $input.all().map(item => item.json);
const allFiles = [...new Set(taskResults.flatMap(r => r.files_written || []))];
const projectId = $('Prepare Planner Input').first().json.project_id;
const projectGoal = $('Prepare Planner Input').first().json.project_goal;
return [{ json: { task_results: taskResults, all_files: allFiles, project_id: projectId, project_goal: projectGoal } }];

const taskResults = $json.task_results || [];
const allFiles = $json.all_files || [];
const projectId = $json.project_id;
const completedTaskIds = taskResults.map(r => r.task_id);
return [{ json: {
  operation: 'set',
  project_id: projectId,
  state: {
    status: 'completed',
    completed_tasks: completedTaskIds,
    files: allFiles
  }
} }];

const operation = $json.operation || 'get';
const projectId = $json.project_id;
if (!projectId) return [{ json: { error: 'project_id required' } }];
const store = $getWorkflowStaticData('global');
if (operation === 'set') {
  const existing = store[projectId] || {};
  store[projectId] = { ...existing, ...$json.state, project_id: projectId, last_updated: new Date().toISOString() };
  return [{ json: store[projectId] }];
}
return [{ json: store[projectId] || { project_id: projectId } }];

const memory = $json;
const aggregated = $('Aggregate All Results').first().json;
return [{ json: {
  status: 'completed',
  project_id: memory.project_id,
  project_goal: memory.goal,
  tasks_completed: (aggregated.task_results || []).length,
  task_results: aggregated.task_results || [],
  files_written: memory.files || []
} }];
